//! Canonical Zones runtime artifacts installed by TIP-1091 at T9.
//!
//! These artifacts were built with the pinned Zones Foundry configuration at
//! [`9a0faf29e5a06b3087afcd8cae0169a3e88785c3`](https://github.com/tempoxyz/zones/commit/9a0faf29e5a06b3087afcd8cae0169a3e88785c3).
//! `ZONE_MESSENGER_RUNTIME` is the constructor-instantiated runtime with
//! `ZONE_FACTORY_ADDRESS` substituted into both immutable references.

use alloy_primitives::{B256, b256, hex};

/// Canonical tempoxyz/zones revision selected for T9 activation.
pub const T9_ZONES_REVISION: &str = "9a0faf29e5a06b3087afcd8cae0169a3e88785c3";

/// Keccak-256 of `ZONE_PORTAL_RUNTIME`.
pub const ZONE_PORTAL_RUNTIME_HASH: B256 =
    b256!("0xd26a7be122403a18eb1df09106a5630ed34cefcc3ec834185aa209c4a5b9fe49");

/// Keccak-256 of `ZONE_VERIFIER_RUNTIME`.
pub const ZONE_VERIFIER_RUNTIME_HASH: B256 =
    b256!("0x161409856e1951ac366af96cfdc403d8ed2395894157d841960e87a329e22ac8");

/// Keccak-256 of the constructor-instantiated `ZONE_MESSENGER_RUNTIME`.
pub const ZONE_MESSENGER_RUNTIME_HASH: B256 =
    b256!("0x7d4b2185698c192b61d23c9989ab547876f92563213b4990b50e2f01b17a00e7");

// TODO: Verify this is the latest correct ZonePortal bytecode before merging this PR.
/// `ZonePortal` `deployedBytecode.object` from the pinned Zones revision.
pub static ZONE_PORTAL_RUNTIME: &[u8] = &hex!(
    ""
);

/// `Verifier` `deployedBytecode.object` from the pinned Zones revision.
pub static ZONE_VERIFIER_RUNTIME: &[u8] = &hex!(
    ""
);

/// `ZoneMessenger` runtime with the canonical ZoneFactory address embedded.
pub static ZONE_MESSENGER_RUNTIME: &[u8] = &hex!(
    ""
);

#[cfg(test)]
mod tests {
    use alloy_primitives::keccak256;

    use super::*;
    use crate::precompiles::ZONE_FACTORY_ADDRESS;

    #[test]
    fn pinned_runtime_hashes_match() {
        assert_eq!(keccak256(ZONE_PORTAL_RUNTIME), ZONE_PORTAL_RUNTIME_HASH);
        assert_eq!(keccak256(ZONE_VERIFIER_RUNTIME), ZONE_VERIFIER_RUNTIME_HASH);
        assert_eq!(
            keccak256(ZONE_MESSENGER_RUNTIME),
            ZONE_MESSENGER_RUNTIME_HASH
        );
    }

    #[test]
    fn messenger_runtime_embeds_zone_factory_authority() {
        let authority_word = [&[0u8; 12][..], ZONE_FACTORY_ADDRESS.as_slice()].concat();
        for offset in [71, 350] {
            assert_eq!(&ZONE_MESSENGER_RUNTIME[offset..offset + 32], authority_word);
        }
    }
}
